    const MOD = 10**9 + 7;
    const freq = new Map();
    const yToX = new Map();

    // Group points by their y-coordinate
    for (const [x, y] of points) {
        if (!yToX.has(y)) {
            yToX.set(y, new Map());
        }
        const xMap = yToX.get(y);
        if (!xMap.has(x)) {
            xMap.set(x, 0);
        }
        xMap.set(x, (xMap.get(x) || 0) + 1);
    }

    let result = 0;

    // For each y-coordinate, process the x-values
    for (const [y, xMap] of yToX.entries()) {
        const xs = Array.from(xMap.keys());
        const counts = Array.from(xMap.values());

        // For each pair of x-values in the same y-coordinate
        for (let i = 0; i < xs.length; i++) {
            for (let j = i + 1; j < xs.length; j++) {
                const x1 = xs[i];
                const x2 = xs[j];
                const c1 = counts[i];
                const c2 = counts[j];

                // Calculate the number of ways to choose two points from each x-value
                const ways1 = (c1 * (c1 - 1)) / 2;
                const ways2 = (c2 * (c2 - 1)) / 2;

                // Add to the result
                result = (result + ways1 * ways2) % MOD;
